import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaBoxOpen, FaTags, FaBarcode, FaWeightHanging, FaMapMarkerAlt, FaCheckCircle, FaFilter, FaTimes, FaChevronDown } from 'react-icons/fa';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 5;

// 1. Sample data for 15 items
const SAMPLE_DATA = [
  { Id: 1, ItemCode: 'IC001', RFIDCode: 'RFID001', SKU: 'SKU001', ProductName: 'Gold Ring', Category: 'Jewelry', Design: 'Classic', Purity: '22K', GrossWt: '5.2', StoneWt: '0.5', StonePcs: 2, DiamondWt: '0.2', DiamondPcs: 1, NetWt: '4.5', Pieces: 1, StoneAmt: '1000', FixedWastage: '0.1', FixedAmt: '200', BoxName: 'Box1', Vendor: 'VendorA', Branch: 'Branch1', CreatedDate: '2024-06-01', PackingWeight: '5.3', TotalWeight: '5.7', Status: 'Active' },
  { Id: 2, ItemCode: 'IC002', RFIDCode: 'RFID002', SKU: 'SKU002', ProductName: 'Silver Chain', Category: 'Jewelry', Design: 'Modern', Purity: '18K', GrossWt: '10.0', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '10.0', Pieces: 1, StoneAmt: '0', FixedWastage: '0.2', FixedAmt: '100', BoxName: 'Box2', Vendor: 'VendorB', Branch: 'Branch2', CreatedDate: '2024-06-02', PackingWeight: '10.1', TotalWeight: '10.3', Status: 'Inactive' },
  { Id: 3, ItemCode: 'IC003', RFIDCode: 'RFID003', SKU: 'SKU003', ProductName: 'Diamond Pendant', Category: 'Jewelry', Design: 'Elegant', Purity: '24K', GrossWt: '2.5', StoneWt: '0.3', StonePcs: 1, DiamondWt: '0.5', DiamondPcs: 2, NetWt: '2.0', Pieces: 1, StoneAmt: '2000', FixedWastage: '0.05', FixedAmt: '300', BoxName: 'Box3', Vendor: 'VendorC', Branch: 'Branch1', CreatedDate: '2024-06-03', PackingWeight: '2.6', TotalWeight: '2.9', Status: 'Active' },
  { Id: 4, ItemCode: 'IC004', RFIDCode: 'RFID004', SKU: 'SKU004', ProductName: 'Platinum Bracelet', Category: 'Jewelry', Design: 'Trendy', Purity: '22K', GrossWt: '7.0', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '7.0', Pieces: 1, StoneAmt: '0', FixedWastage: '0.15', FixedAmt: '250', BoxName: 'Box4', Vendor: 'VendorD', Branch: 'Branch3', CreatedDate: '2024-06-04', PackingWeight: '7.1', TotalWeight: '7.3', Status: 'Inactive' },
  { Id: 5, ItemCode: 'IC005', RFIDCode: 'RFID005', SKU: 'SKU005', ProductName: 'Gold Necklace', Category: 'Jewelry', Design: 'Classic', Purity: '22K', GrossWt: '15.0', StoneWt: '1.0', StonePcs: 3, DiamondWt: '0.3', DiamondPcs: 1, NetWt: '13.7', Pieces: 1, StoneAmt: '3000', FixedWastage: '0.2', FixedAmt: '400', BoxName: 'Box5', Vendor: 'VendorA', Branch: 'Branch2', CreatedDate: '2024-06-05', PackingWeight: '15.2', TotalWeight: '15.6', Status: 'Active' },
  { Id: 6, ItemCode: 'IC006', RFIDCode: 'RFID006', SKU: 'SKU006', ProductName: 'Silver Anklet', Category: 'Jewelry', Design: 'Modern', Purity: '18K', GrossWt: '8.0', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '8.0', Pieces: 1, StoneAmt: '0', FixedWastage: '0.1', FixedAmt: '150', BoxName: 'Box6', Vendor: 'VendorB', Branch: 'Branch1', CreatedDate: '2024-06-06', PackingWeight: '8.1', TotalWeight: '8.2', Status: 'Inactive' },
  { Id: 7, ItemCode: 'IC007', RFIDCode: 'RFID007', SKU: 'SKU007', ProductName: 'Diamond Earring', Category: 'Jewelry', Design: 'Elegant', Purity: '24K', GrossWt: '3.0', StoneWt: '0.2', StonePcs: 1, DiamondWt: '0.4', DiamondPcs: 2, NetWt: '2.4', Pieces: 2, StoneAmt: '2500', FixedWastage: '0.07', FixedAmt: '350', BoxName: 'Box7', Vendor: 'VendorC', Branch: 'Branch3', CreatedDate: '2024-06-07', PackingWeight: '3.1', TotalWeight: '3.3', Status: 'Active' },
  { Id: 8, ItemCode: 'IC008', RFIDCode: 'RFID008', SKU: 'SKU008', ProductName: 'Gold Bangle', Category: 'Jewelry', Design: 'Classic', Purity: '22K', GrossWt: '6.5', StoneWt: '0.4', StonePcs: 2, DiamondWt: '0.1', DiamondPcs: 1, NetWt: '6.0', Pieces: 2, StoneAmt: '1200', FixedWastage: '0.12', FixedAmt: '220', BoxName: 'Box8', Vendor: 'VendorD', Branch: 'Branch2', CreatedDate: '2024-06-08', PackingWeight: '6.6', TotalWeight: '6.8', Status: 'Inactive' },
  { Id: 9, ItemCode: 'IC009', RFIDCode: 'RFID009', SKU: 'SKU009', ProductName: 'Silver Pendant', Category: 'Jewelry', Design: 'Modern', Purity: '18K', GrossWt: '4.0', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '4.0', Pieces: 1, StoneAmt: '0', FixedWastage: '0.09', FixedAmt: '120', BoxName: 'Box9', Vendor: 'VendorA', Branch: 'Branch1', CreatedDate: '2024-06-09', PackingWeight: '4.1', TotalWeight: '4.2', Status: 'Active' },
  { Id: 10, ItemCode: 'IC010', RFIDCode: 'RFID010', SKU: 'SKU010', ProductName: 'Diamond Ring', Category: 'Jewelry', Design: 'Elegant', Purity: '24K', GrossWt: '2.2', StoneWt: '0.1', StonePcs: 1, DiamondWt: '0.3', DiamondPcs: 1, NetWt: '1.8', Pieces: 1, StoneAmt: '1800', FixedWastage: '0.04', FixedAmt: '180', BoxName: 'Box10', Vendor: 'VendorB', Branch: 'Branch2', CreatedDate: '2024-06-10', PackingWeight: '2.3', TotalWeight: '2.5', Status: 'Inactive' },
  { Id: 11, ItemCode: 'IC011', RFIDCode: 'RFID011', SKU: 'SKU011', ProductName: 'Gold Chain', Category: 'Jewelry', Design: 'Classic', Purity: '22K', GrossWt: '12.0', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '12.0', Pieces: 1, StoneAmt: '0', FixedWastage: '0.18', FixedAmt: '210', BoxName: 'Box11', Vendor: 'VendorC', Branch: 'Branch3', CreatedDate: '2024-06-11', PackingWeight: '12.1', TotalWeight: '12.3', Status: 'Active' },
  { Id: 12, ItemCode: 'IC012', RFIDCode: 'RFID012', SKU: 'SKU012', ProductName: 'Platinum Ring', Category: 'Jewelry', Design: 'Trendy', Purity: '22K', GrossWt: '5.5', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '5.5', Pieces: 1, StoneAmt: '0', FixedWastage: '0.11', FixedAmt: '160', BoxName: 'Box12', Vendor: 'VendorD', Branch: 'Branch1', CreatedDate: '2024-06-12', PackingWeight: '5.6', TotalWeight: '5.7', Status: 'Inactive' },
  { Id: 13, ItemCode: 'IC013', RFIDCode: 'RFID013', SKU: 'SKU013', ProductName: 'Gold Earring', Category: 'Jewelry', Design: 'Classic', Purity: '22K', GrossWt: '3.8', StoneWt: '0.2', StonePcs: 1, DiamondWt: '0.1', DiamondPcs: 1, NetWt: '3.5', Pieces: 2, StoneAmt: '900', FixedWastage: '0.06', FixedAmt: '140', BoxName: 'Box13', Vendor: 'VendorA', Branch: 'Branch2', CreatedDate: '2024-06-13', PackingWeight: '3.9', TotalWeight: '4.0', Status: 'Active' },
  { Id: 14, ItemCode: 'IC014', RFIDCode: 'RFID014', SKU: 'SKU014', ProductName: 'Silver Bracelet', Category: 'Jewelry', Design: 'Modern', Purity: '18K', GrossWt: '7.2', StoneWt: '0.0', StonePcs: 0, DiamondWt: '0.0', DiamondPcs: 0, NetWt: '7.2', Pieces: 1, StoneAmt: '0', FixedWastage: '0.13', FixedAmt: '170', BoxName: 'Box14', Vendor: 'VendorB', Branch: 'Branch3', CreatedDate: '2024-06-14', PackingWeight: '7.3', TotalWeight: '7.4', Status: 'Inactive' },
  { Id: 15, ItemCode: 'IC015', RFIDCode: 'RFID015', SKU: 'SKU015', ProductName: 'Diamond Necklace', Category: 'Jewelry', Design: 'Elegant', Purity: '24K', GrossWt: '16.0', StoneWt: '1.2', StonePcs: 4, DiamondWt: '0.6', DiamondPcs: 2, NetWt: '14.2', Pieces: 1, StoneAmt: '3500', FixedWastage: '0.22', FixedAmt: '500', BoxName: 'Box15', Vendor: 'VendorC', Branch: 'Branch1', CreatedDate: '2024-06-15', PackingWeight: '16.2', TotalWeight: '16.7', Status: 'Active' },
];

const Inventory = ({ clientCode, userInfo: userInfoProp }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState(SAMPLE_DATA);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);
  const [showFilter, setShowFilter] = useState(false);

  // Refs for outside click
  const filterPopupRef = useRef(null);
  const filterBtnRef = useRef(null);

  // Get userInfo from props or localStorage
  const [userInfo, setUserInfo] = useState(userInfoProp || null);
  useEffect(() => {
    if (!userInfoProp) {
      const stored = localStorage.getItem('userInfo');
      if (stored) {
        try {
          setUserInfo(JSON.parse(stored));
        } catch {}
      }
    }
  }, [userInfoProp]);

  // Close filter popup on outside click
  useEffect(() => {
    if (!showFilter) return;
    function handleClick(e) {
      if (
        filterPopupRef.current &&
        !filterPopupRef.current.contains(e.target) &&
        filterBtnRef.current &&
        !filterBtnRef.current.contains(e.target)
      ) {
        setFilterAnim(false);
        setTimeout(() => setShowFilter(false), 200);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [showFilter]);

  // Responsive helper
  const isMobile = window.innerWidth < 600;

  // Animation for filter dropdown
  const [filterAnim, setFilterAnim] = useState(false);
  const openFilter = () => { setShowFilter(true); setTimeout(() => setFilterAnim(true), 10); };
  const closeFilter = () => { setFilterAnim(false); setTimeout(() => setShowFilter(false), 200); };

  // Table header and cell styles
  const thStyle = {
    fontWeight: 700,
    color: '#222',
    background: '#f4f8ff',
    fontSize: 14,
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    letterSpacing: 0.1,
    height: 36,
    whiteSpace: 'nowrap',
  };

  const tdStyle = {
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    fontSize: 13,
    height: 32,
    color: '#222',
    fontWeight: 500,
    letterSpacing: 0.1,
    whiteSpace: 'nowrap',
  };

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  // Unified filter dropdown state
  const handleFilterChangeUnified = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f7f8fa', fontFamily: 'Poppins, Inter, sans-serif' }}>
      <Header userInfo={userInfo ? userInfo : { ClientCode: clientCode, Username: '' }} />
      <div className="container py-4" style={{ maxWidth: 1500 }}>
        {/* Title */}
        <div className="text-center pt-8 pb-4">
          <h1 style={{
            fontWeight: 800,
            fontSize: 32,
            borderBottom: '3px solid #2563eb',
            display: 'inline-block',
            paddingBottom: 10,
            marginBottom: 0,
            letterSpacing: 0.5,
            color: '#222',
            fontFamily: 'Poppins, Inter, sans-serif',
            textAlign: 'center',
            textTransform: 'none',
            lineHeight: 1.2
          }}>
            Inventory Labelled List
          </h1>
        </div>
        {/* Top bar */}
        <div className={isMobile ? 'd-flex flex-column align-items-stretch mb-6 px-2' : 'd-flex flex-wrap align-items-center justify-content-between mb-6 px-2'} style={{ maxWidth: 1300, margin: '0 auto', gap: isMobile ? 12 : 0 }}>
          {/* Search */}
          <div className="d-flex align-items-center mb-2 mb-md-0" style={{ flex: 1 }}>
            <div style={{ position: 'relative', width: isMobile ? '100%' : 340 }}>
              <input
                type="text"
                placeholder="Search by Product Name, Category, SKU..."
                value={search}
                onChange={handleSearchChange}
                style={{
                  borderRadius: 10,
                  border: '1.5px solid #e5e7eb',
                  padding: '10px 16px 10px 44px',
                  width: '100%',
                  boxShadow: '0 1.5px 6px #0001',
                  fontSize: 15,
                  background: '#fff',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  outline: 'none',
                  transition: 'box-shadow 0.2s',
                  fontWeight: 500
                }}
                onFocus={e => e.target.style.boxShadow = '0 2px 8px #2563eb22'}
                onBlur={e => e.target.style.boxShadow = '0 1.5px 6px #0001'}
              />
              <span style={{
                position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)',
                color: '#9ca3af', fontSize: 20
              }}>
                <FaSearch />
              </span>
            </div>
          </div>
          {/* Export and Filter Buttons */}
          <div className={isMobile ? 'd-flex flex-column gap-2 mt-3' : 'd-flex align-items-center gap-3'} style={{ width: isMobile ? '100%' : 'auto', justifyContent: isMobile ? 'center' : 'flex-end' }}>
            <button
              onClick={handleExport}
              style={{
                border: '1.5px solid #28a745',
                color: '#fff',
                background: '#28a745',
                borderRadius: 10,
                fontWeight: 700,
                height: 44,
                fontSize: 15,
                padding: '0 26px',
                width: isMobile ? '100%' : 'auto',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'background 0.2s',
                boxShadow: '0 2px 8px #28a74511',
                marginRight: isMobile ? 0 : 0,
                gap: 10,
                fontFamily: 'Poppins, Inter, sans-serif',
                letterSpacing: 0.1
              }}
              onMouseOver={e => e.currentTarget.style.background = '#218838'}
              onMouseOut={e => e.currentTarget.style.background = '#28a745'}
            >
              <FaFileExcel style={{ marginRight: 8 }} /> Export to Excel
            </button>
            <button
              ref={filterBtnRef}
              onClick={openFilter}
              style={{
                border: '1.5px solid #2563eb',
                color: '#2563eb',
                background: '#f4f8ff',
                borderRadius: 10,
                fontWeight: 700,
                height: 44,
                fontSize: 15,
                padding: '0 26px',
                width: isMobile ? '100%' : 'auto',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'background 0.2s',
                boxShadow: '0 2px 8px #2563eb11',
                gap: 10,
                fontFamily: 'Poppins, Inter, sans-serif',
                letterSpacing: 0.1
              }}
              onMouseOver={e => { e.currentTarget.style.background = '#e6f0ff'; e.currentTarget.style.color = '#1746a2'; }}
              onMouseOut={e => { e.currentTarget.style.background = '#f4f8ff'; e.currentTarget.style.color = '#2563eb'; }}
            >
              <FaFilter style={{ marginRight: 8 }} /> Filter
            </button>
            {showFilter && (
              <div
                ref={filterPopupRef}
                style={{
                  position: 'absolute',
                  top: 54,
                  right: 0,
                  background: '#fff',
                  borderRadius: 16,
                  boxShadow: '0 8px 32px #0002',
                  padding: 0,
                  minWidth: isMobile ? 320 : 480,
                  zIndex: 10,
                  border: '1.5px solid #ccc',
                  display: 'flex',
                  flexDirection: 'column',
                  overflow: 'hidden',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  opacity: filterAnim ? 1 : 0,
                  transform: filterAnim ? 'translateY(0)' : 'translateY(-16px)',
                  transition: 'opacity 0.2s, transform 0.2s',
                }}
              >
                <button onClick={closeFilter} style={{ position: 'absolute', top: 10, right: 14, background: 'none', border: 'none', color: '#28a745', fontSize: 20, cursor: 'pointer', zIndex: 2 }}><FaTimes /></button>
                <div style={{ padding: '24px 24px 8px 24px', display: 'flex', flexDirection: 'column', gap: 18 }}>
                  <div style={{ fontWeight: 700, color: '#28a745', fontSize: 20, marginBottom: 8, letterSpacing: 0.2 }}>Filter Inventory</div>
                  <div style={{
                    display: 'grid',
                    gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr',
                    gap: 18,
                  }}>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Product Name</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.ProductName || ''} onChange={e => handleFilterChangeUnified('ProductName', e.target.value)}><option value="">All</option>{getUnique('ProductName').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Category</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.CategoryName || ''} onChange={e => handleFilterChangeUnified('CategoryName', e.target.value)}><option value="">All</option>{getUnique('CategoryName').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>ItemCode</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.ItemCode || ''} onChange={e => handleFilterChangeUnified('ItemCode', e.target.value)}><option value="">All</option>{getUnique('ItemCode').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Gross Wt</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.GrossWt || ''} onChange={e => handleFilterChangeUnified('GrossWt', e.target.value)}><option value="">All</option>{getUnique('GrossWt').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Net Wt</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.NetWt || ''} onChange={e => handleFilterChangeUnified('NetWt', e.target.value)}><option value="">All</option>{getUnique('NetWt').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Branch</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.BranchName || ''} onChange={e => handleFilterChangeUnified('BranchName', e.target.value)}><option value="">All</option>{getUnique('BranchName').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                    <div>
                      <label style={{ fontWeight: 500, color: '#555', fontSize: 14, marginBottom: 4, display: 'block' }}>Status</label>
                      <select className="form-select form-select-sm mb-2" style={{ borderRadius: 6, padding: '8px 12px', fontSize: 14, border: '1.5px solid #ccc', background: '#fafbfc', outline: 'none', width: '100%' }} value={filters.Status || ''} onChange={e => handleFilterChangeUnified('Status', e.target.value)}><option value="">All</option>{getUnique('Status').map(val => <option key={val} value={val}>{val}</option>)}</select>
                    </div>
                  </div>
                  <a href="#" onClick={e => { e.preventDefault(); setFilters({}); }} style={{ color: '#28a745', fontWeight: 500, fontSize: 14, marginTop: 8, textDecoration: 'underline', alignSelf: 'flex-end' }}>Reset Filters</a>
                </div>
              </div>
            )}
          </div>
        </div>
        {/* Table */}
        <div className="overflow-x-auto" style={{ maxWidth: 1400, margin: '32px auto 8px auto', padding: 16, boxSizing: 'border-box', background: '#fff', borderRadius: 16, boxShadow: '0 6px 24px rgba(0,0,0,0.07)', fontFamily: 'Poppins, Inter, sans-serif', display: 'flex', flexDirection: 'column', justifyContent: 'flex-start', maxHeight: 'calc(100vh - 200px)', minHeight: 200 }}>
          <table className="table align-middle mb-0" style={{ width: '100%', minWidth: 1200, background: '#fff', borderRadius: 16, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0, fontSize: '1rem', fontFamily: 'Poppins, Inter, sans-serif', tableLayout: 'auto' }}>
            <thead style={{ background: '#f4f8ff', borderTopLeftRadius: 16, borderTopRightRadius: 16, boxShadow: '0 2px 8px #0001' }}>
              <tr style={{ borderRadius: 16, height: 36 }}>
                <th style={{ ...thStyle, width: 40 }}>Sr No</th>
                <th style={{ ...thStyle, width: 90 }}>Item Code</th>
                <th style={{ ...thStyle, width: 110 }}>RFID Code</th>
                <th style={{ ...thStyle, width: 80 }}>SKU</th>
                <th style={{ ...thStyle, minWidth: 120 }}>Product Name</th>
                <th style={{ ...thStyle, minWidth: 90 }}>Category</th>
                <th style={{ ...thStyle, minWidth: 90 }}>Design</th>
                <th style={{ ...thStyle, width: 70 }}>Purity</th>
                <th style={{ ...thStyle, width: 80 }}>Gross Wt</th>
                <th style={{ ...thStyle, width: 80 }}>Stone Wt</th>
                <th style={{ ...thStyle, width: 80 }}>Stone Pcs</th>
                <th style={{ ...thStyle, width: 90 }}>Diamond Wt</th>
                <th style={{ ...thStyle, width: 90 }}>Diamond Pcs</th>
                <th style={{ ...thStyle, width: 80 }}>Net Wt</th>
                <th style={{ ...thStyle, width: 70 }}>Pieces</th>
                <th style={{ ...thStyle, width: 90 }}>Stone Amt</th>
                <th style={{ ...thStyle, width: 110 }}>Fixed Wastage</th>
                <th style={{ ...thStyle, width: 90 }}>Fixed Amt</th>
                <th style={{ ...thStyle, minWidth: 90 }}>Box Name</th>
                <th style={{ ...thStyle, minWidth: 90 }}>Vendor</th>
                <th style={{ ...thStyle, minWidth: 90 }}>Branch</th>
                <th style={{ ...thStyle, minWidth: 110 }}>Created Date</th>
                <th style={{ ...thStyle, width: 110 }}>Packing Weight</th>
                <th style={{ ...thStyle, width: 110 }}>Total Weight</th>
                <th style={{ ...thStyle, minWidth: 80 }}>Status</th>
              </tr>
            </thead>
            <tbody>
              {paginatedLabels.map((label, idx) => (
                <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0', height: 32 }}
                  onMouseOver={e => e.currentTarget.style.background = '#e6f0ff'}
                  onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                >
                  <td style={{ ...tdStyle, width: 40, textAlign: 'center', fontWeight: 600 }}>{(page - 1) * PAGE_SIZE + idx + 1}</td>
                  <td style={{ ...tdStyle, width: 90 }}>{label.ItemCode}</td>
                  <td style={{ ...tdStyle, width: 110 }}>{label.RFIDCode}</td>
                  <td style={{ ...tdStyle, width: 80 }}>{label.SKU}</td>
                  <td style={{ ...tdStyle, minWidth: 120 }}>{label.ProductName}</td>
                  <td style={{ ...tdStyle, minWidth: 90 }}>{label.CategoryName || label.Category}</td>
                  <td style={{ ...tdStyle, minWidth: 90 }}>{label.Design}</td>
                  <td style={{ ...tdStyle, width: 70 }}>{label.Purity}</td>
                  <td style={{ ...tdStyle, width: 80 }}>{label.GrossWt}</td>
                  <td style={{ ...tdStyle, width: 80 }}>{label.StoneWt}</td>
                  <td style={{ ...tdStyle, width: 80 }}>{label.StonePcs}</td>
                  <td style={{ ...tdStyle, width: 90 }}>{label.DiamondWt}</td>
                  <td style={{ ...tdStyle, width: 90 }}>{label.DiamondPcs}</td>
                  <td style={{ ...tdStyle, width: 80 }}>{label.NetWt}</td>
                  <td style={{ ...tdStyle, width: 70 }}>{label.Pieces}</td>
                  <td style={{ ...tdStyle, width: 90 }}>{label.StoneAmt}</td>
                  <td style={{ ...tdStyle, width: 110 }}>{label.FixedWastage}</td>
                  <td style={{ ...tdStyle, width: 90 }}>{label.FixedAmt}</td>
                  <td style={{ ...tdStyle, minWidth: 90 }}>{label.BoxName}</td>
                  <td style={{ ...tdStyle, minWidth: 90 }}>{label.Vendor}</td>
                  <td style={{ ...tdStyle, minWidth: 90 }}>{label.BranchName || label.Branch}</td>
                  <td style={{ ...tdStyle, minWidth: 110 }}>{label.CreatedDate ? new Date(label.CreatedDate).toLocaleDateString() : ''}</td>
                  <td style={{ ...tdStyle, width: 110 }}>{label.PackingWeight}</td>
                  <td style={{ ...tdStyle, width: 110 }}>{label.TotalWeight}</td>
                  <td style={{ ...tdStyle, minWidth: 80 }}>
                    <span className={`badge`} style={{
                      background: label.Status === 'Active' ? '#d4f7df' : '#ffe5e5',
                      color: label.Status === 'Active' ? '#2ecc71' : '#e74c3c',
                      fontWeight: 700,
                      fontSize: 12,
                      padding: '2px 8px',
                      borderRadius: 12,
                      border: 'none',
                      letterSpacing: 0.2,
                      minWidth: 50,
                      display: 'inline-block',
                      textAlign: 'center',
                      fontFamily: 'Poppins, Inter, sans-serif'
                    }}>{label.Status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {/* Pagination below table card, compact and right-aligned */}
        {totalPages > 1 && !search && (
          <div className="d-flex justify-content-end align-items-center" style={{ marginTop: 12, marginBottom: 24, maxWidth: 1400, marginLeft: 'auto', marginRight: 'auto', padding: '0 16px', boxSizing: 'border-box', background: '#fff' }}>
            <nav>
              <ul className="pagination mb-0" style={{ background: '#fff', borderRadius: 10, boxShadow: '0 1px 6px #2563eb11', padding: '6px 14px', display: 'flex', flexWrap: 'nowrap', gap: 4 }}>
                <li className={`page-item${page === 1 ? ' disabled' : ''}`}> <button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1rem', borderRadius: 7, padding: '4px 10px', transition: 'background 0.2s' }} onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                {[...Array(totalPages)].map((_, idx) => (
                  <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}> <button className="page-link" style={{ border: 'none', background: idx + 1 === page ? '#2563eb' : 'none', color: idx + 1 === page ? '#fff' : '#2563eb', fontWeight: 600, fontSize: '1rem', borderRadius: 7, margin: '0 2px', minWidth: 28, padding: '4px 10px', boxShadow: idx + 1 === page ? '0 1px 4px #2563eb22' : 'none', transition: 'background 0.2s, color 0.2s' }} onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button></li>
                ))}
                <li className={`page-item${page === totalPages ? ' disabled' : ''}`}> <button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1rem', borderRadius: 7, padding: '4px 10px', transition: 'background 0.2s' }} onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
              </ul>
            </nav>
          </div>
        )}
      </div>
    </div>
  );
};

export default Inventory;
